        # Accept various date formats for Sep 14, 2025
        has_deadline = bool(re.search(r'09[/\-]14[/\-]2025|9[/\-]14[/\-]2025|september\s+14|sep\.?\s*14|2025-09-14', text))

        if has_early_discount and has_harrison and has_invoice and has_amount and has_deadline:
